1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_UNIT_PREMIUM = 25;
5	
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const HIGH_ENCHANTMENT_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const FIRST_INSURANCE_RATE = 0.1;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_THRESHOLD_YEARS = 2;
12	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: COMPONENT_UNIT_PREMIUM,
20	  moonstone: COMPONENT_UNIT_PREMIUM,
21	};
22	
23	const INSURANCE_VALUES: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const DEDUCTIBLE = 100;
33	const CAP_MULTIPLIER = 2;
34	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
35	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	interface Item {
40	  type: string;
41	  material?: string;
42	  enchantment?: number;
43	  cursed?: boolean;
44	}
45	
46	interface QuoteStep {
47	  op: "quote";
48	  items: Item[];
49	}
50	
51	interface Damage {
52	  itemType: string;
53	  amount: number;
54	}
55	
56	interface ClaimStep {
57	  op: "claim";
58	  policy: number;
59	  incident: { cause?: string; damages: Damage[] };
60	}
61	
62	type Step = QuoteStep | ClaimStep;
63	
64	interface Scenario {
65	  customer: { yearsWithMHPCO: number };
66	  steps: Step[];
67	}
68	
69	interface PolicyState {
70	  items: Item[];
71	  insuranceSum: number;
72	  cap: number;
73	  remainingCap: number;
74	}
75	
76	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
77	const isMainItem = (item: Item): boolean => !isComponent(item);
78	
79	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
80	
81	const countsByType = (items: Item[]): Map<string, number> =>
82	  items.reduce((counts, item) => {
83	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
84	    return counts;
85	  }, new Map<string, number>());
86	
87	const componentGroupPremium = (count: number): number =>
88	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
89	
90	const sumComponentPremiums = (components: Item[]): number =>
91	  Array.from(countsByType(components).values()).reduce(
92	    (total, count) => total + componentGroupPremium(count),
93	    0,
94	  );
95	
96	const sumMainItemPremiums = (mainItems: Item[]): number =>
97	  mainItems.reduce((total, item) => total + basePremiumFor(item), 0);
98	
99	const policyBasePremium = (items: Item[]): number =>
100	  sumMainItemPremiums(items.filter(isMainItem)) +
101	  sumComponentPremiums(items.filter(isComponent));
102	
103	const curseRate = (item: Item): number => (item.cursed ? CURSE_SURCHARGE_RATE : 0);
104	
105	const highEnchantmentRate = (item: Item): number =>
106	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0;
107	
108	const itemModifierRate = (item: Item): number => curseRate(item) + highEnchantmentRate(item);
109	
110	const itemModifierSurcharge = (item: Item): number =>
111	  isComponent(item) ? 0 : basePremiumFor(item) * itemModifierRate(item);
112	
113	const sumItemModifiers = (items: Item[]): number =>
114	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
115	
116	interface CustomerContext {
117	  yearsWithMHPCO: number;
118	  isFollowUpContract: boolean;
119	}
120	
121	const loyaltyDiscountRate = (ctx: CustomerContext): number =>
122	  ctx.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;
123	
124	const followUpDiscountRate = (ctx: CustomerContext): number =>
125	  ctx.isFollowUpContract ? FOLLOW_UP_DISCOUNT_RATE : 0;
126	
127	const policyModifierRate = (ctx: CustomerContext): number =>
128	  FIRST_INSURANCE_RATE - loyaltyDiscountRate(ctx) - followUpDiscountRate(ctx);
129	
130	const policyModifierAmount = (policyBase: number, ctx: CustomerContext): number =>
131	  policyBase * policyModifierRate(ctx);
132	
133	const computeQuote = (step: QuoteStep, ctx: CustomerContext) => {
134	  const policyBase = policyBasePremium(step.items);
135	  const itemSurcharges = sumItemModifiers(step.items);
136	  const policyMods = policyModifierAmount(policyBase, ctx);
137	  const premium = policyBase + itemSurcharges + policyMods + PROCESSING_FEE;
138	  return { premium: Math.ceil(premium) };
139	};
140	
141	const insuranceSumOf = (items: Item[]): number =>
142	  items.reduce((total, item) => total + (INSURANCE_VALUES[item.type] ?? 0), 0);
143	
144	const createPolicy = (items: Item[]): PolicyState => {
145	  const insuranceSum = insuranceSumOf(items);
146	  const cap = insuranceSum * CAP_MULTIPLIER;
147	  return { items, insuranceSum, cap, remainingCap: cap };
148	};
149	
150	const hasHighClaimEnchantment = (item: Item | undefined): boolean =>
151	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
152	
153	const reimbursedAmount = (damage: Damage, item: Item | undefined): number =>
154	  hasHighClaimEnchantment(item) ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE : damage.amount;
155	
156	const damagePayout = (damage: Damage, item: Item | undefined): number =>
157	  Math.max(0, reimbursedAmount(damage, item) - DEDUCTIBLE);
158	
159	const findItem = (items: Item[], itemType: string): Item | undefined =>
160	  items.find((i) => i.type === itemType);
161	
162	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
163	  damages.reduce((total, damage) => total + damagePayout(damage, findItem(items, damage.itemType)), 0);
164	
165	const processClaim = (step: ClaimStep, policy: PolicyState) => {
166	  const uncappedPayout = sumDamagePayouts(step.incident.damages, policy.items);
167	  const payout = Math.min(uncappedPayout, policy.remainingCap);
168	  policy.remainingCap -= payout;
169	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
170	};
171	
172	interface ScenarioState {
173	  policies: PolicyState[];
174	  quoteCount: number;
175	  yearsWithMHPCO: number;
176	}
177	
178	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUMS));
179	
180	const isKnownItem = (item: Item): boolean => KNOWN_ITEM_TYPES.has(item.type);
181	
182	const assertAllValid = <T>(
183	  collection: T[],
184	  isValid: (element: T) => boolean,
185	  buildError: (invalid: T) => string,
186	): void => {
187	  const invalid = collection.find((element) => !isValid(element));
188	  if (invalid) {
189	    throw new Error(buildError(invalid));
190	  }
191	};
192	
193	const validateQuoteItems = (items: Item[]): void =>
194	  assertAllValid(items, isKnownItem, (item) => `Unknown item type: ${item.type}`);
195	
196	const handleQuoteStep = (step: QuoteStep, state: ScenarioState) => {
197	  validateQuoteItems(step.items);
198	  const ctx: CustomerContext = {
199	    yearsWithMHPCO: state.yearsWithMHPCO,
200	    isFollowUpContract: state.quoteCount > 0,
201	  };
202	  state.quoteCount += 1;
203	  state.policies.push(createPolicy(step.items));
204	  return computeQuote(step, ctx);
205	};
206	
207	const insuredTypesOf = (items: Item[]): Set<string> =>
208	  new Set(items.map((item) => item.type));
209	
210	const validateClaimDamages = (damages: Damage[], policyItems: Item[]): void => {
211	  const insuredTypes = insuredTypesOf(policyItems);
212	  assertAllValid(
213	    damages,
214	    (damage) => insuredTypes.has(damage.itemType),
215	    (damage) => `Damage references item not in policy: ${damage.itemType}`,
216	  );
217	  const insuredCounts = countsByType(policyItems);
218	  const damageCounts = new Map<string, number>();
219	  for (const damage of damages) {
220	    damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
221	  }
222	  for (const [itemType, count] of damageCounts) {
223	    if (count > (insuredCounts.get(itemType) ?? 0)) {
224	      throw new Error(`Damage entries for ${itemType} exceed insured count`);
225	    }
226	  }
227	};
228	
229	const handleClaimStep = (step: ClaimStep, state: ScenarioState) => {
230	  const policy = state.policies[step.policy];
231	  validateClaimDamages(step.incident.damages, policy.items);
232	  return processClaim(step, policy);
233	};
234	
235	export const runScenario = (input: unknown): unknown => {
236	  const scenario = input as Scenario;
237	  const state: ScenarioState = {
238	    policies: [],
239	    quoteCount: 0,
240	    yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
241	  };
242	  const results = scenario.steps.map((step) =>
243	    step.op === "quote" ? handleQuoteStep(step, state) : handleClaimStep(step, state),
244	  );
245	  return { results };
246	};
